#!/bin/bash
# Generated by cc-statusline v1.3.2 (https://www.npmjs.com/package/@chongdashu/cc-statusline)
# Custom Claude Code statusline - Created: 2025-09-01T10:09:24.608Z
# Theme: detailed | Colors: true | Features: directory, git, git-commit, model, context, session
STATUSLINE_VERSION="1.3.2"

input=$(cat)

# Check if jq is available
HAS_JQ=0
if command -v jq >/dev/null 2>&1; then
  HAS_JQ=1
fi

# ---- color helpers (force colors for Claude Code) ----
use_color=1
[ -n "$NO_COLOR" ] && use_color=0

C() { if [ "$use_color" -eq 1 ]; then printf '\033[%sm' "$1"; fi; }
RST() { if [ "$use_color" -eq 1 ]; then printf '\033[0m'; fi; }

# ---- modern sleek colors (bold) ----
dir_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;117m'; fi; }    # sky blue
model_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;147m'; fi; }  # light purple
version_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;180m'; fi; } # soft yellow
cc_version_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;146m'; fi; } # light steel blue
style_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;139m'; fi; } # muted purple
rst() { if [ "$use_color" -eq 1 ]; then printf '\033[0m'; fi; }

# ---- time helpers ----
to_epoch() {
  ts="$1"
  if command -v gdate >/dev/null 2>&1; then gdate -d "$ts" +%s 2>/dev/null && return; fi
  date -u -j -f "%Y-%m-%dT%H:%M:%S%z" "${ts/Z/+0000}" +%s 2>/dev/null && return
  python3 - "$ts" <<'PY' 2>/dev/null
import sys, datetime
s=sys.argv[1].replace('Z','+00:00')
print(int(datetime.datetime.fromisoformat(s).timestamp()))
PY
}

fmt_time_hm() {
  epoch="$1"
  if date -r 0 +%s >/dev/null 2>&1; then date -r "$epoch" +"%H:%M"; else date -d "@$epoch" +"%H:%M"; fi
}

progress_bar() {
  pct="${1:-0}"; width="${2:-10}"
  [[ "$pct" =~ ^[0-9]+$ ]] || pct=0; ((pct<0))&&pct=0; ((pct>100))&&pct=100
  filled=$(( pct * width / 100 )); empty=$(( width - filled ))
  printf '%*s' "$filled" '' | tr ' ' '='
  printf '%*s' "$empty" '' | tr ' ' '-'
}

unicode_bar() {
  pct="${1:-0}"; width="${2:-10}"
  [[ "$pct" =~ ^[0-9]+$ ]] || pct=0; ((pct<0))&&pct=0; ((pct>100))&&pct=100
  filled=$(( pct * width / 100 )); empty=$(( width - filled ))
  printf '%*s' "$filled" '' | tr ' ' '█'
  printf '%*s' "$empty" '' | tr ' ' '░'
}

fmt_tokens() {
  local n="$1"
  if [ "$n" -ge 1000000 ]; then
    local m=$(( n / 1000000 ))
    local frac=$(( (n % 1000000) / 100000 ))
    if [ "$frac" -eq 0 ]; then
      printf '%sM' "$m"
    else
      printf '%s.%sM' "$m" "$frac"
    fi
  elif [ "$n" -ge 1000 ]; then
    printf '%sk' "$(( n / 1000 ))"
  else
    printf '%s' "$n"
  fi
}

# git utilities
num_or_zero() { v="$1"; [[ "$v" =~ ^[0-9]+$ ]] && echo "$v" || echo 0; }

# ---- JSON extraction utilities ----
# Pure bash JSON value extractor (fallback when jq not available)
extract_json_string() {
  local json="$1"
  local key="$2"
  local default="${3:-}"
  
  # For nested keys like workspace.current_dir, get the last part
  local field="${key##*.}"
  field="${field%% *}"  # Remove any jq operators
  
  # Try to extract string value (quoted)
  local value=$(echo "$json" | grep -o "\"\${field}\"[[:space:]]*:[[:space:]]*\"[^\"]*\"" | head -1 | sed 's/.*:[[:space:]]*"\([^"]*\)".*/\1/')
  
  # Convert escaped backslashes to forward slashes for Windows paths
  if [ -n "$value" ]; then
    value=$(echo "$value" | sed 's/\\\\/\//g')
  fi
  
  # If no string value found, try to extract number value (unquoted)
  if [ -z "$value" ] || [ "$value" = "null" ]; then
    value=$(echo "$json" | grep -o "\"\${field}\"[[:space:]]*:[[:space:]]*[0-9.]\+" | head -1 | sed 's/.*:[[:space:]]*\([0-9.]\+\).*/\1/')
  fi
  
  # Return value or default
  if [ -n "$value" ] && [ "$value" != "null" ]; then
    echo "$value"
  else
    echo "$default"
  fi
}

# ---- basics ----
if [ "$HAS_JQ" -eq 1 ]; then
  current_dir=$(echo "$input" | jq -r '.workspace.current_dir // .cwd // "unknown"' 2>/dev/null | sed "s|^$HOME|~|g")
  model_name=$(echo "$input" | jq -r '.model.display_name // "Claude"' 2>/dev/null)
  model_version=$(echo "$input" | jq -r '.model.version // ""' 2>/dev/null)
  session_id=$(echo "$input" | jq -r '.session_id // ""' 2>/dev/null)
  cc_version=$(echo "$input" | jq -r '.version // ""' 2>/dev/null)
  output_style=$(echo "$input" | jq -r '.output_style.name // ""' 2>/dev/null)
else
  # Bash fallback for JSON extraction
  # Extract current_dir from workspace object - look for the pattern workspace":{"current_dir":"..."}
  current_dir=$(echo "$input" | grep -o '"workspace"[[:space:]]*:[[:space:]]*{[^}]*"current_dir"[[:space:]]*:[[:space:]]*"[^"]*"' | sed 's/.*"current_dir"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/' | sed 's/\\\\/\//g')
  
  # Fall back to cwd if workspace extraction failed
  if [ -z "$current_dir" ] || [ "$current_dir" = "null" ]; then
    current_dir=$(echo "$input" | grep -o '"cwd"[[:space:]]*:[[:space:]]*"[^"]*"' | sed 's/.*"cwd"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/' | sed 's/\\\\/\//g')
  fi
  
  # Fallback to unknown if all extraction failed
  [ -z "$current_dir" ] && current_dir="unknown"
  current_dir=$(echo "$current_dir" | sed "s|^$HOME|~|g")
  
  # Extract model name from nested model object
  model_name=$(echo "$input" | grep -o '"model"[[:space:]]*:[[:space:]]*{[^}]*"display_name"[[:space:]]*:[[:space:]]*"[^"]*"' | sed 's/.*"display_name"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/')
  [ -z "$model_name" ] && model_name="Claude"
  # Model version is in the model ID, not a separate field  
  model_version=""  # Not available in Claude Code JSON
  session_id=$(extract_json_string "$input" "session_id" "")
  # CC version is at the root level
  cc_version=$(echo "$input" | grep -o '"version"[[:space:]]*:[[:space:]]*"[^"]*"' | head -1 | sed 's/.*"version"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/')
  # Output style is nested
  output_style=$(echo "$input" | grep -o '"output_style"[[:space:]]*:[[:space:]]*{[^}]*"name"[[:space:]]*:[[:space:]]*"[^"]*"' | sed 's/.*"name"[[:space:]]*:[[:space:]]*"\([^"]*\)".*/\1/')
fi

# ---- git colors ----
git_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;150m'; fi; }  # soft green
rst() { if [ "$use_color" -eq 1 ]; then printf '\033[0m'; fi; }

# ---- git ----
git_branch=""
git_commit=""
if git rev-parse --git-dir >/dev/null 2>&1; then
  git_branch=$(git branch --show-current 2>/dev/null || git rev-parse --short HEAD 2>/dev/null)
  # Get latest commit hash and message
  git_commit=$(git log -1 --format="%s" 2>/dev/null | head -c 60)
  [ ${#git_commit} -eq 60 ] && git_commit="${git_commit}..."
fi

# ---- context window calculation ----
context_pct=""
context_used_pct=0
tokens_fmt=""
max_fmt=""
context_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;111m'; fi; }  # steel blue

# Determine max context based on model
get_max_context() {
  local model_name="$1"
  case "$model_name" in
    *"1M"*|*"1m"*)
      echo "1000000"  # 1M context (e.g. Opus 4.6 1M)
      ;;
    *"Opus 4"*|*"opus 4"*|*"Opus"*|*"opus"*)
      echo "200000"  # 200K for Opus (default)
      ;;
    *"Sonnet 4"*|*"sonnet 4"*|*"Sonnet 3.5"*|*"sonnet 3.5"*|*"Sonnet"*|*"sonnet"*)
      echo "200000"  # 200K for Sonnet 3.5+ and 4.x
      ;;
    *"Haiku 3.5"*|*"haiku 3.5"*|*"Haiku 4"*|*"haiku 4"*|*"Haiku"*|*"haiku"*)
      echo "200000"  # 200K for modern Haiku
      ;;
    *"Claude 3 Haiku"*|*"claude 3 haiku"*)
      echo "100000"  # 100K for original Claude 3 Haiku
      ;;
    *)
      echo "200000"  # Default to 200K
      ;;
  esac
}

if [ -n "$session_id" ] && [ "$HAS_JQ" -eq 1 ]; then
  MAX_CONTEXT=$(get_max_context "$model_name")
  
  # Find session file by searching project directories for the session ID
  session_file=""
  found=$(find "$HOME/.claude/projects" -maxdepth 2 -name "${session_id}.jsonl" -print -quit 2>/dev/null)
  if [ -n "$found" ]; then
    session_file="$found"
  fi

  if [ -n "$session_file" ] && [ -f "$session_file" ]; then
    # Get the latest input token count from the session file
    latest_tokens=$(tail -20 "$session_file" | jq -r 'select(.message.usage) | .message.usage | ((.input_tokens // 0) + (.cache_read_input_tokens // 0))' 2>/dev/null | tail -1)
    
    if [ -n "$latest_tokens" ] && [ "$latest_tokens" -gt 0 ]; then
      context_used_pct=$(( latest_tokens * 100 / MAX_CONTEXT ))
      tokens_fmt=$(fmt_tokens "$latest_tokens")
      max_fmt=$(fmt_tokens "$MAX_CONTEXT")

      # Color based on usage (green → amber → red as context fills up)
      if [ "$context_used_pct" -ge 80 ]; then
        context_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;203m'; fi; }  # coral red
      elif [ "$context_used_pct" -ge 60 ]; then
        context_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;215m'; fi; }  # amber
      else
        context_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;111m'; fi; }  # steel blue
      fi

      context_pct="set"
    fi
  fi
fi

# ---- effort level ----
effort_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;75m'; fi; }  # default: medium blue

# Read effort level
effort_level=""

# 1. Statusline JSON input (future-proof if Anthropic adds it)
if [ "$HAS_JQ" -eq 1 ]; then
  effort_level=$(echo "$input" | jq -r '.effort // empty' 2>/dev/null)
fi

# 2. Parse session JSONL for most recent effort change (~26ms)
#    Catches both /effort commands and /model effort changes immediately
if [ -z "$effort_level" ] && [ -n "$session_file" ] && [ -f "$session_file" ]; then
  effort_level=$(tail -c 262144 "$session_file" 2>/dev/null | python3 -c "
import sys, json, re
effort = ''
for line in sys.stdin:
    try:
        e = json.loads(line)
        if e.get('type') != 'user': continue
        msg = e.get('message', '')
        c = msg.get('content', '') if isinstance(msg, dict) else msg if isinstance(msg, str) else ''
        if not isinstance(c, str): continue
        if '<command-name>/effort' in c:
            m = re.search(r'command-args>(low|medium|high|max|auto)</command-args', c)
            if m: effort = m.group(1)
        elif 'local-command-stdout' in c and 'effort' in c:
            clean = re.sub(r'\\x1b\[\d+m|\x1b\[\d+m', '', c)
            m = re.search(r'with\s+(low|medium|high|max)\s+effort', clean)
            if m: effort = m.group(1)
    except: pass
print(effort)
" 2>/dev/null)
  case "$effort_level" in low|medium|high|max|auto) ;; *) effort_level="" ;; esac
fi

# 3. Stop hook file as fallback
if [ -z "$effort_level" ] && [ -f "$HOME/.claude/effort_level" ]; then
  effort_level=$(cat "$HOME/.claude/effort_level" 2>/dev/null | tr -d '[:space:]')
fi

[ -z "$effort_level" ] && effort_level="max"

# Color effort by intensity
case "$effort_level" in
  low)    effort_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;111m'; fi; } ;;  # steel blue
  medium) effort_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;150m'; fi; } ;;  # soft green
  high)   effort_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;215m'; fi; } ;;  # amber
  max)    effort_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;203m'; fi; } ;;  # coral red
  auto)   effort_color() { if [ "$use_color" -eq 1 ]; then printf '\033[1;38;5;147m'; fi; } ;;  # light purple
esac

# ---- render statusline ----
# Line 1: Directory
printf '📁 %s%s%s' "$(dir_color)" "$current_dir" "$(rst)"

# Line 2: Model and version
line3="🤖 $(model_color)${model_name}$(rst)"
if [ -n "$cc_version" ] && [ "$cc_version" != "null" ]; then
  line3="$line3  📟 $(cc_version_color)v${cc_version}$(rst)"
fi

# Line 3: Context bar and effort level
line4=""
if [ -n "$context_pct" ]; then
  ctx_bar=$(unicode_bar "$context_used_pct" 17)
  line4="🧠 $(context_color)${ctx_bar} ${tokens_fmt} / ${max_fmt}$(rst)"
fi
if [ -n "$effort_level" ]; then
  if [ -n "$line4" ]; then
    line4="$line4  $(effort_color)${effort_level}$(rst)"
  else
    line4="$(effort_color)${effort_level}$(rst)"
  fi
fi
if [ -z "$line4" ] && [ -z "$context_pct" ]; then
  line4="🧠 $(context_color)░░░░░░░░░░░░░░░░░$(rst)"
fi

# Print all lines
printf '\n%s' "$line3"
if [ -n "$line4" ]; then
  printf '\n%s' "$line4"
fi
printf '\n'
